#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define int long long
using namespace std;
inline long long read()
{
	long long res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=5e4+10,Mod=1e9+7,Inv2=500000004;
int ch[N*40][2],ll[N*40],rr[N*40],siz[N*40],a[N],cnt=1;
inline void ins(int k,int Q)
{
	int p=1;drep(29,0,i)
	{
		int &x=ch[p][(k>>i)&1];
		x?++rr[p=x]:(p=x=++cnt,ll[p]=rr[p]=Q);
	}++siz[p];
}
int num,pth,cur,n,Rt[N];long long K,sum[40][N][2];
inline int dfs(int a,int Res)
{
	int p=1,num=0,pth=a^Res;
	drep(29,0,i)
	{
		bool suf=(pth>>i)&1;if(((Res>>i)&1)^1)num+=siz[ch[p][suf^1]];
		if(!ch[p][suf])return num;p=ch[p][suf];
	}
	return num;
}
inline void Init(int u=1)
{
	if(ch[u][0])Init(ch[u][0]),siz[u]+=siz[ch[u][0]];
	if(ch[u][1])Init(ch[u][1]),siz[u]+=siz[ch[u][1]];
}
inline bool check(int Q)
{
	int res=0;rep(1,n,i){res+=dfs(a[i],Q);}
	return res<K;
}
int Num;
inline int Qry(int l,int r,int val,int Res)
{
	if(!l||!r)return 0;long long res=0;Num+=(r-l+1);
	drep(29,0,i)if(((Res>>i)&1)^1)
	{
		res=(res+((1ll*(sum[i][r][((val>>i)&1)^1]-sum[i][l-1][((val>>i)&1)^1])%Mod)<<i)%Mod)%Mod;
	}
	return res;
}
int tmp[N];inline long long Add(long long x,long long y){return (x+y)%Mod;}
inline int ask(int l,int r,int val) {
	if(!l||!r) return 0;
	int res=0;
	for(register int d=29;d>=0;--d) res=Add(res,1ll*(sum[d][r][(val>>d&1)^1]-sum[d][l-1][(val>>d&1)^1])*((1ll<<d)%Mod)%Mod);
	return res;
}
signed main()
{
	n=read();K=read()<<1;if(!K){puts("0");return 0;}
	int L=0,R=(1ll<<30),Mid,Res=(1ll<<30);
	rep(1,n,i)a[i]=read();sort(a+1,a+n+1);rep(1,n,i)ins(a[i],i);Init();
	siz[0]=ll[0]=rr[0]=0;
	while(L<=R)(check(Mid=(L+R)>>1)?R=Mid-1:(L=Mid+1,Res=Mid));++Res;
	int nn=0;rep(1,n,i)nn+=dfs(a[i],Res);K-=nn;
//	printf("%lld\n",Res);
	rep(1,n,i)drep(29,0,j)
	{
		sum[j][i][0]=sum[j][i-1][0];
		sum[j][i][1]=sum[j][i-1][1];
		++sum[j][i][(a[i]>>j)&1];
	}
//	rep(1,n,i){drep(29,0,j)printf("%lld ",sum[j][i][0]);puts("");}
//	rep(1,cnt,i)printf("%lld : %lld %lld\n",i,ll[i],rr[i]);
	int ans=1ll*Res*K%Mod;
//	printf("ans %lld %lld %lld\n",Res,K,ans);
	rep(1,n,i)tmp[i]=1; 
	for(register int d=29;d>=0;--d)
	{
		int x=Res>>d&1;
		if(!x){for(register int i=1;i<=n;++i) ans=Add(ans,ask(ll[ch[tmp[i]][(a[i]>>d&1)^1]],rr[ch[tmp[i]][(a[i]>>d&1)^1]],a[i]));}
		for(register int i=1;i<=n;++i) tmp[i]=ch[tmp[i]][(a[i]>>d&1)^x];
	}
//	printf("%d\n",ans);
	printf("%lld\n",1ll*ans*Inv2%Mod);
	
}
